import { useRef } from 'react';
import { useLatest } from './useLatest';
import { useProxyRef } from '@universe-design/react-utilities';

const config: MutationObserverInit = {
  attributes: true,
  characterData: true,
  childList: true,
  subtree: true,
};

export function useMutationObserverRef<T extends HTMLElement>(
  callback: MutationCallback,
  { options = config, skipElement }: { options?: MutationObserverInit; skipElement?: (node: T) => boolean } = {},
) {
  const callbackRef = useLatest(callback);
  const observerRef = useRef<MutationObserver | null>(null);
  const ref = useProxyRef<T>(null, node => {
    if (!node || (skipElement && skipElement(node))) {
      return;
    }
    observerRef.current?.disconnect();
    const observer = new MutationObserver(callbackRef.current);
    observer.observe(node, options);
    observerRef.current = observer;
  });

  return ref;
}
